function main() {
  let content = fs.readFileSync(TRANSLATIONS_FILE, 'utf8');
  const langs = ['fr','es','de','it','pt','ru','nl','zh','ja','ko','ar','hi','bn','pa','th','vi','id','ms','tl','tr','pl','uk','ro','el','cs','sv','da','fi','no','he','sw','ne'];
  for (const lang of langs) {
    const langPattern = new RegExp(`(  ${lang}: \\{[\\s\\S]*?)(\\n  \\},)`, 'm');
    const match = content.match(langPattern);
    if (!match) { console.log(`WARNING: ${lang} not found`); continue; }
    const existingKeys = new Set();
    const keyRegex = /"([^"]+)":\s*"/g;
    let km;
    while ((km = keyRegex.exec(match[1])) !== null) existingKeys.add(km[1]);
    const newEntries = [];
    for (const [key, translations] of Object.entries(M)) {
      if (!existingKeys.has(key) && translations[lang]) {
        const escaped = translations[lang].replace(/\\/g, '\\\\').replace(/"/g, '\\"');
        newEntries.push(`    "${key}": "${escaped}"`);
      }
    }
    if (newEntries.length > 0) {
      const insertion = ',\n' + newEntries.join(',\n');
      content = content.replace(langPattern, `$1${insertion}$2`);
      console.log(`${lang}: +${newEntries.length}`);
    }
  }
  fs.writeFileSync(TRANSLATIONS_FILE, content, 'utf8');
  console.log('BATCH 6 FINAL complete. ALL 668 keys should now be translated.');
}
main();
